import org.springframework.beans.factory.config.BeanFactoryPostProcessor;
import org.springframework.beans.factory.config.ConfigurableListableBeanFactory;
import org.springframework.beans.factory.support.BeanDefinitionRegistry;
import org.springframework.beans.factory.support.BeanDefinitionRegistryPostProcessor;
import org.springframework.stereotype.Component;

@Component
public class ProxyBeanRegistrar implements BeanDefinitionRegistryPostProcessor {

    @Override
    public void postProcessBeanDefinitionRegistry(BeanDefinitionRegistry registry) throws BeansException {
        // 从之前例子中的 findTargetInterfaces 方法获取接口类
        List<Class<?>> targetInterfaces = findTargetInterfaces("com.example"); // 填写你的基包名

        for (Class<?> targetInterface : targetInterfaces) {
            Object proxy = CglibProxyGenerator.createProxy(targetInterface);

            // 使用 GeneratedBeanNameGenerator 或自定义策略生成bean名称
            String beanName = targetInterface.getName() + "CglibProxy";

            // 将代理注册为Spring管理的Bean
            BeanDefinitionBuilder builder = BeanDefinitionBuilder.genericBeanDefinition(targetInterface, () -> proxy);
            registry.registerBeanDefinition(beanName, builder.getBeanDefinition());
        }
    }

    @Override
    public void postProcessBeanFactory(ConfigurableListableBeanFactory beanFactory) throws BeansException {
        // No need to implement this for our use case
    }

    private List<Class<?>> findTargetInterfaces(String basePackage) {
        // 实现基于ClassPathScanningCandidateComponentProvider的查找逻辑
    }
}
```

这样，您就能在Spring容器启动时动态地为那些实现了目标接口的接口创建基于CGLIB的`MethodInterceptor`代理，并将这些代理注册到Spring容器中。这允许您在应用的其他部分通过常规的Spring注入方式使用这些代理对象，实现动态代理逻辑的自定义和应用。

确保你已经实现了`findTargetInterfaces`方法来查找所有符合要求的目标接口。这个实现通常涉及Spring的`ClassPathScanningCandidateComponentProvider`用于扫描并找到所有实现了`BaseInterface`接口的类或接口。

